solution_code:
#include <iostream>

int main()
{
    int quarters{};
    int dimes{};
    int nickels{};
    int pennies{};
    std::cin >> quarters >> dimes >> nickels >> pennies;

    int total_cents{ quarters * 25 + dimes * 10 + nickels * 5 + pennies };

    std::cout << "Total cents: " << total_cents << '\n';

    return 0;
}
